class CounterfactualSimulator:
    """三假设反事实仿真引擎。

    simulate(action, user_context) → CounterfactualResult
    """

    def __init__(self, config: dict | None = None):
        self._config = config or {}
        self._sim_cfg = config.get("simulation", {}) if config else {}

    def simulate(self, action: dict, user_context: dict | None = None) -> dict:
        """对 DSL 动作进行反事实仿真。

        Args:
            action: PolicyComposer 输出的 action dict
            user_context: 当前用户上下文（可选）

        Returns: {
            "risk_flagged": bool,        # 任一假设下恶化
            "risk_score": float,          # 综合风险得分 [0,1]
            "hypotheses": list[dict],    # 三个假设的推演结果
            "baseline_score": float,      # 基线推演得分
            "recommendation": str,        # "proceed"|"caution"|"block"
        }
        """
```

```python
def _compute_risk_score(self, hypotheses: list[CounterfactualHypothesis],
                          weights: dict) -> float:
    """综合各假设的风险得分 [0,1]"""
    w = weights or {}
    w_best = w.get("best_case", 0.3)
    w_worst = w.get("worst_case", 0.4)
    w_alt = w.get("alt_path", 0.3)

    total_risk = 0.0
    for h in hypotheses:
        weight = {
            "best_case": w_best,
            "worst_case": w_worst,
            "alt_path": w_alt,
        }.get(h.name, 0.33)
        # 风险贡献 = weight * (1.0 - baseline_adj_score)
        risk_contrib = weight * (1.0 - (0.5 - h.delta_score))
        total_risk += risk_contrib

    return round(max(0.0, min(1.0, total_risk)), 4)

def _recommend(self, risk_flagged: bool, risk_score: float) -> str:
    """生成推荐动作。"""
    if risk_flagged and risk_score > 0.6:
        return "block"
    elif risk_flagged:
        return "caution"
    return "proceed"
